var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":"……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"......제이나!!","JPN":"……ジェイナ！！","ENG":"Jaina!","TWN":"……婕娜！！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제이나! 정신이 드나!","JPN":"ジェイナ！　気がついたか？","ENG":"Jaina! Wake up!","TWN":"婕娜！你清醒了嗎！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님......?","JPN":"副司令官……？","ENG":"Deputy Commander?","TWN":"副司令官大人……！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"훗...... 지금까지 봐온 망상들 중에 제일 생생한걸.","JPN":"フッ……これまで見てきた妄想の中でも、一番生々しい。","ENG":"Heh... It's the most vivid delusion I've ever seen.","TWN":"呵呵……這是我至目前為止所幻想出最栩栩如生的一次了。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"나도 아직 미련이 많이 남아있었나 보네.","JPN":"私にもまだ未練が残っていたのか。","ENG":"I guess I still have a lot of regrets.","TWN":"看來我還有很多留戀啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......망상이 아니다.","JPN":"……妄想ではない。","ENG":"I'm not a delusion.","TWN":"……不是幻想。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"나다, 도미닉 킹 레지날드.","JPN":"私だ、ドミニーク・キング・レジナルド。","ENG":"It's me, Dominic King Reginald.","TWN":"是我，多明尼克·金·雷吉納德。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"촌구석 교회에 숨어 있던 널 구해준 사람이지.","JPN":"教会に隠れていたお前を救った人間だ。","ENG":"I'm the person who saved you in that village church.","TWN":"把躲在村莊角落教會的你救出來的人。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그리고 지금 다시 한 번 더 널 구하러 왔다. 그러니 정신 차려라.","JPN":"そして、今再びお前を助けに来た。だからしっかりしろ。","ENG":"And I'm here to save you once again. So wake up.","TWN":"現在我又一次來救你了。所以快清醒過來吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"진짜......","JPN":"本当に……","ENG":"You...","TWN":"真的……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"진짜 레지날드 부사령관님인가요?","JPN":"本当にレジナルド副司令官ですか？","ENG":"You're the real Deputy Commander Reginald?","TWN":"真的是多明尼克副司令官嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"아니, 그럴리가...... 부사령관님이 어떻게 이곳에 오신 거죠?","JPN":"いや、そんなはずが……副司令官がどうしてここにいらっしゃるんですか？","ENG":"No, that can't be... How can you be here?","TWN":"不、不可能……副司令官大人怎麼會來這裡？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"이곳은 차원함선으로도 도달할 수 없는 곳인데......","JPN":"ここは次元艦船でも到達できない場所なのに.......","ENG":"Even a dimensional ship can't reach this place...","TWN":"這裡是次元戰艦也無法到達的地方……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......모종의 조력자가 있었다.","JPN":"……協力者がいた。","ENG":"I had some help.","TWN":"……我有某種意義上的幫手。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"모두 이야기하자면 길어, 일단 여기에서 빠져나가도록 하지.","JPN":"話せば長い、とりあえずここから抜け出そう。","ENG":"It's a long story. Let's get out of here first.","TWN":"說來話長，先從這裡出去吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"하, 하지만 전 차원통로를 통과하면서 하반신이 네임리스 원의 육체에 파묻혀 버렸습니다.","JPN":"で、ですが、私は次元通路を通過した時、下半身がネームレスワンの身体に埋もれてしまいました。","ENG":"B-but my lower torso was buried inside the Nameless One's body as we passed through the dimensional passage.","TWN":"但、但是我通過次元通道的時候，下半身被無名1的肉身壓住了。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};